VALUES
  ('judicial-cf446b4c-moex-00154', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於旅遊營業人變更旅遊內容，下列敘述，何者正確？ 旅遊營業人僅得於因不可抗力或不可歸責之事由時，始得變更旅遊內容 旅遊營業人任意變更旅遊行程內容項目，旅客僅得終止契約，不得解除契約 旅遊營業人在銷售行程資料載明「航班及飯店僅供參考」，即得因目的地當地情形隨時變更航班 與飯店 旅遊營業人任意變更旅遊行程內容項目，旅客僅得減少價金', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00155', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '關於契約成立方式之一，乃要約與承諾合致。下列何者非屬要約？ 超商架上標定售價之麵包  土豆伯沿街叫賣好吃之燒土豆 投幣式販賣機中標示價格之飲品  水果攤販標示花蓮大西瓜一顆500元', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00156', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '依民法規定，下列關於保證之敘述，何者錯誤？ 保證債務，除契約另有訂定外，不包含主債務之利息 保證人得主張主債務契約不成立之抗辯 保證人得以主債務人對於債權人已具抵銷適狀之債權，主張抵銷 主債務人受破產宣告者，保證人不得主張先訴抗辯權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00157', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙訂立甲所有A屋之買賣契約，乙並已先支付部分價金於甲。未料在甲應交付A屋於乙、並 為移轉所有權登記前，A屋因受鄰屋屋主丙不慎引發火災波及而滅失。下列敘述，何者錯誤？ 甲得請求丙賠償因A屋滅失所受之損害 乙得請求甲返還其已支付之部分價金 乙得請求丙賠償其因A屋滅失所受之損害 甲免負交付A屋及移轉A屋所有權於乙之義務', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00158', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲將收藏多年價值新臺幣（下同）60萬元之古董花瓶委託乙清潔上釉，未料乙竟將此花瓶整理後 用自己名義以80萬元出售給收藏家丙後，將價金拿去酒店花光。下列敘述，何者正確？ 甲得向乙主張不法管理，請其返還80萬元 甲得向乙主張成立侵權行為，請求乙賠償80萬元，並得請求精神慰撫金 甲得向乙主張不當得利，請乙返還80萬元。但因利益已花完，故已無須返還 甲得主張乙無權代理，請求乙返還80萬元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00159', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '以所有之意思，二十年間和平、公然、繼續占有他人未登記之不動產者，關於其法律效果，下列 敘述，何者正確？ 立即取得該不動產之所有權  得請求登記為不動產所有人 得向法院訴請判決為所有人  得請求該他人協同辦理登記', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00160', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '不動產抵押權，乃以不動產為標的物之擔保物權。下列何者非不動產抵押權效力所及？ 以建築物為抵押者，於抵押權設定後附加於建築物，具有獨立性之物 抵押物滅失之殘餘物 抵押物之從物 抵押物扣押後自抵押物分離，而得由抵押人收取之天然孳息', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00161', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲乙丙丁四人為A地分別共有人，就A地之使用訂立分管契約。嗣後，甲將其A地應有部分讓 與戊。關於分管契約之拘束力，下列敘述，何者正確？ 不論戊是否知悉，分管契約對於戊均有拘束力 戊明知分管契約時，分管契約始對戊有拘束力 分管契約於登記後，對於受讓人戊始有拘束力 分管契約是債權契約，絕不可能對戊生拘束力', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00162', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲、乙與丙登記為A地之公同共有人。關於公同共有人之權利，下列敘述，何者正確？ 甲得自由處分A地 甲得自由處分其應有部分 甲得隨時請求分割A地 丁無權占有A地。甲得以自己名義，請求丁返還A地於全體', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00163', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '稱不動產物權行為者，謂以不動產物權變動為直接內容之法律行為。關於不動產物權行為，下列 敘述，何者錯誤？ 不動產物權行為是不要物行為 不動產物權行為以登記為生效要件 不動產物權行為應以書面為之 不動產物權行為，非經公證人作成公證書，不生效力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
